from typing import List

def productExceptSelf(nums: List[int]) -> List[int]:
    length = len(nums)
    output = [1] * length

    for i in range(length):
        product = 1
        for j in range(length):
            if i != j:
                product *= nums[j]
        output[i] = product

    return output

